class PaginationController extends GetxController {
  var items = <String>[].obs;
  var currentPage = 1.obs;
  var hasMore = true.obs;
  var isLoading = false.obs;

  @override
  void onInit() {
    super.onInit();
    fetchItems();
  }

  Future<void> fetchItems() async {
    if (isLoading.value || !hasMore.value) return;
    isLoading.value = true;
    try {
      final newItems = await fetchItems(currentPage.value);
      if (newItems.isEmpty) {
        hasMore.value = false;
      } else {
        items.addAll(newItems);
        currentPage.value++;
      }
    } catch (e) {
      Get.snackbar('Error', e.toString());
    } finally {
      isLoading.value = false;
    }
  }

  void refreshItems() {
    items.clear();
    currentPage.value = 1;
    hasMore.value = true;
    fetchItems();
  }
}

class PaginationDemo extends StatelessWidget {
  final controller = Get.put(PaginationController());
  final ScrollController scrollController = ScrollController();

  @override
  void initState() {
    super.initState();
    scrollController.addListener(() {
      if (scrollController.position.pixels == scrollController.position.maxScrollExtent) {
        controller.fetchItems();
      }
    });
  }

  @override
  void dispose() {
    scrollController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Pagination Demo'),
        actions: [
          IconButton(
            icon: Icon(Icons.refresh),
            onPressed: controller.refreshItems,
          ),
        ],
      ),
      body: RefreshIndicator(
        onRefresh: () async => controller.refreshItems(),
        child: Obx(() => ListView.builder(
          controller: scrollController,
          itemCount: controller.items.length + (controller.hasMore.value ? 1 : 0),
          itemBuilder: (_, index) {
            if (index == controller.items.length) {
              return Center(
                child: Padding(
